import mongoose from 'mongoose';
import UserSetting from "./model/UserSetting.js";

async function runExample() {
    try {
        // Connect to MongoDB
        await mongoose.connect(
            'mongodb+srv://REMOVED_CLUSTER_INFO'
        );
        console.log('Connected to MongoDB');

        // TEMP user id
        const userId = '000000000000000000000001';

        // CREATE a new user setting
        const userSetting = await UserSetting.create({
            userId,
            dailyStudyMinutes: 180,
            studyDaysPerWeek: 6,
            breakDuration: 20,
            maxWeeklyWorkload: 900
        });

        console.log('Created UserSetting:', userSetting);

        // UPDATE user setting
        userSetting.dailyStudyMinutes = 200;
        userSetting.breakDuration = 25;
        await userSetting.save();

        console.log('Updated UserSetting:', userSetting);

        // READ user setting by userId (later will be used to find settings for the logged in user/$lookup in aggregation)
        const settingsForUser = await UserSetting.findOne({ userId });
        console.log('UserSetting for userId:', settingsForUser);

        // DELETE user setting
        const deleted = await UserSetting.deleteOne({ userId });
        console.log('Deleted UserSetting:', deleted);

    } catch (err) {
        console.error('Error running example:', err);
    } finally {
        await mongoose.disconnect();
        console.log('Disconnected from MongoDB');
    }
}

runExample();